 1	import React, { FC } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { isEmpty } from '@kubevirt-utils/utils/utils';
 5	import {
 6	  Button,
 7	  Grid,
 8	  GridItem,
 9	  Panel,
10	  PanelMain,
11	  Skeleton,
12	  Text,
13	  TextVariants,
14	} from '@patternfly/react-core';
15	import { PlusCircleIcon } from '@patternfly/react-icons';
16	
17	import SSHAuthKeyRow from './components/SSHAuthKeyRow/SSHAuthKeyRow';
18	import useSSHAuthKeys from './hooks/useSSHAuthKeys';
19	
20	import './SSHAuthKeysList.scss';
21	
22	const SSHAuthKeysList: FC = () => {
23	  const { t } = useKubevirtTranslation();
24	  const {
25	    authKeyRows,
26	    loaded,
27	    onAuthKeyAdd,
28	    onAuthKeyChange,
29	    onAuthKeyDelete,
30	    selectableProjects,
31	  } = useSSHAuthKeys();
32	
33	  if (!loaded) return <Skeleton />;
34	
35	  return (
36	    <>
37	      <Panel isScrollable>
38	        <PanelMain maxHeight="12.25rem">
39	          <Grid>
40	            <GridItem span={5}>
41	              <Text component={TextVariants.h6}>{t('Project')}</Text>
42	            </GridItem>
43	            <GridItem span={1} />
44	            <GridItem span={5}>
45	              <Text component={TextVariants.h6}>{t('Public SSH key')}</Text>
46	            </GridItem>
47	          </Grid>
48	          {authKeyRows?.map((row) => (
49	            <SSHAuthKeyRow
50	              isRemoveDisabled={authKeyRows.length === 1 && isEmpty(row.projectName)}
51	              key={row.id}
52	              onAuthKeyChange={onAuthKeyChange}
53	              onAuthKeyDelete={onAuthKeyDelete}
54	              row={row}
55	              selectableProjects={selectableProjects}
56	            />
57	          ))}
58	        </PanelMain>
59	      </Panel>
60	      <Button
61	        className="add-row-btn"
62	        icon={<PlusCircleIcon />}
63	        isDisabled={isEmpty(selectableProjects)}
64	        isInline
65	        onClick={onAuthKeyAdd}
66	        variant="link"
67	      >
68	        {t('Add public SSH key to project')}
69	      </Button>
70	    </>
71	  );
72	};
73	
74	export default SSHAuthKeysList;

